        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: '',
        imageUrl: '',
        municipalities: ['Laoag City', 'Batac City', 'Pagudpud'],
        damage_details: [],
