        damage_facilities: '',
        work_suspension: false,
        assistance_provided: '',
        remark: '',
        remark_related_incidents: '',
        remark_casualties: '',
        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: '',
        imageUrl: '',
        municipalities: ['Vigan City', 'Candon City', 'Santa Maria'],
        damage_details: [],
        equipment_details: [],
        affected_staff: []
    },
    'PSTO-La Union': {
        warning_signals: {},
        general_weather: '',
        related_incidents: 0,
        casualties: 0,
        power_status: '',
        communication_lines: '',
        damage_facilities: '',
        work_suspension: false,
        assistance_provided: '',
        remark: '',
        remark_related_incidents: '',
        remark_casualties: '',
        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: '',
        imageUrl: '',
        municipalities: ['San Fernando', 'Bauang', 'Agoo', 'Luna', 'Bacnotan', 'Bangar', 'San Juan'],
        damage_details: [],
        equipment_details: [],
        affected_staff: []
    },
    'PSTO-Pangasinan': {
        warning_signals: {},
        general_weather: '',
        related_incidents: 0,
        casualties: 0,
        power_status: '',
        communication_lines: '',
        damage_facilities: '',
        work_suspension: false,
        assistance_provided: '',
        remark: '',
        remark_related_incidents: '',
        remark_casualties: '',
        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: '',
        imageUrl: '',
        municipalities: ['Lingayen', 'Dagupan', 'Alaminos'],
        damage_details: [],
        equipment_details: [],
        affected_staff: []
    },
    'PSTO-Ilocos Sur - FO': {
        warning_signals: {},
        general_weather: '',
        related_incidents: 0,
        casualties: 0,
        power_status: '',
        communication_lines: '',
        damage_facilities: '',
        work_suspension: false,
        assistance_provided: '',
        remark: '',
        remark_related_incidents: '',
        remark_casualties: '',
        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: '',
        imageUrl: '',
        municipalities: ['Vigan City', 'Candon City', 'Santa Maria'],
        damage_details: [],
        equipment_details: [],
        affected_staff: []
    },
    'PSTO-Pangasinan - FO': {
        warning_signals: {},
        general_weather: '',
        related_incidents: 0,
        casualties: 0,
        power_status: '',
        communication_lines: '',
        damage_facilities: '',
        work_suspension: false,
        assistance_provided: '',
        remark: '',
        remark_related_incidents: '',
        remark_casualties: '',
        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: '',
        imageUrl: '',
        municipalities: ['Lingayen', 'Dagupan', 'Alaminos'],
        damage_details: [],
        equipment_details: [],
        affected_staff: []
    },
};

const TYPHOON_HISTORY_KEY = 'dash_typhoon_history';
const DEFAULT_EVENTS = [];

const DEFAULT_USERS = [
    { id: 1, name: 'Admin User', email: 'admin@dostregion1.ph', office: 'PSTO-La Union', role: 'SADMIN', status: 'Active', password: 'admin123', profileImage: '' },
    { id: 2, name: 'Regional Admin', email: 'admin-ilocosnorte@dostregion1.ph', office: 'PSTO-Ilocos Norte', role: 'ADMIN', status: 'Active', password: 'admin123', profileImage: '' },
    { id: 3, name: 'General User', email: 'user-ilocossur@dostregion1.ph', office: 'PSTO-Ilocos Sur', role: 'USER', status: 'Active', password: 'user123', profileImage: '' },
];

const loadFromStorage = (key, defaultValue) => {
    const stored = localStorage.getItem(key);
    if (stored) {
        try { return JSON.parse(stored); } catch (e) { return defaultValue; }
    }
    return defaultValue;
};

const saveToStorage = (key, data) => localStorage.setItem(key, JSON.stringify(data));

const archiveOldEvents = (events) => {
    const sevenDaysAgo = new Date();
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
    return events.map(event => {
        if (event.status !== 'archived' && event.endDateTime) {
            const endDate = new Date(event.endDateTime);
            if (endDate < sevenDaysAgo) {
                return { ...event, status: 'archived', deployment: event.deployment === 'Deployed' ? 'Draft' : event.deployment };
            }
        }
        return event;
    });
};

const fetchLiveWeather = async () => {
    const lat = 16.5;
    const lon = 120.5;
    try {
        const response = await fetch(
            `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true&timezone=Asia/Manila`
        );
        const data = await response.json();
        if (data.current_weather) {
            const w = data.current_weather;
            const temp = w.temperature;
            const weatherCode = w.weathercode;
            let condition = '';
            if (weatherCode === 0) condition = 'Clear sky';
            else if (weatherCode === 1 || weatherCode === 2) condition = 'Partly cloudy';
            else if (weatherCode === 3) condition = 'Overcast';
            else if (weatherCode >= 51 && weatherCode <= 67) condition = 'Drizzle / Rain';
            else if (weatherCode >= 80 && weatherCode <= 99) condition = 'Rain / Thunderstorm';
            else condition = 'Cloudy / Variable';
            return { temp: Math.round(temp), condition, windSpeed: w.windspeed };
        }
    } catch (err) {
        console.error('Weather fetch failed:', err);
    }
    return null;
};

const deepClone = (obj) => JSON.parse(JSON.stringify(obj));

const Dashboard = ({ onLogout, currentUser }) => {
    // ----------------------------- STATE -----------------------------
    const [officesData, setOfficesData] = useState(() => {
        const stored = loadFromStorage('dash_officesData', DEFAULT_OFFICE_DATA);
        const merged = { ...DEFAULT_OFFICE_DATA, ...stored };
        Object.keys(merged).forEach(key => {
            if (!merged[key].damage_details) merged[key].damage_details = [];
            if (!merged[key].equipment_details) merged[key].equipment_details = [];
            if (!merged[key].affected_staff) merged[key].affected_staff = [];
        });
        return merged;
    });

    const [events, setEvents] = useState(() => archiveOldEvents(loadFromStorage('dash_events', DEFAULT_EVENTS)));
    const [typhoonHistory, setTyphoonHistory] = useState(() => loadFromStorage(TYPHOON_HISTORY_KEY, []));
    const [users, setUsers] = useState(() => loadFromStorage('dash_users', DEFAULT_USERS));
    const [notifications, setNotifications] = useState(() => loadFromStorage('dash_notifications', []));
    const [liveWeather, setLiveWeather] = useState(null);
    const [weatherLoading, setWeatherLoading] = useState(true);
    const [activeMenu, setActiveMenu] = useState(() => loadFromStorage('dash_activeMenu', 'dashboard'));
    const [selectedOffice, setSelectedOffice] = useState(currentUser?.office || 'PSTO-La Union');
    const [editMode, setEditMode] = useState(false);
    const [formData, setFormData] = useState(null);
    const [newMunicipality, setNewMunicipality] = useState('');
    const [newSignal, setNewSignal] = useState(1);
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [showAddModal, setShowAddModal] = useState(false);
    const [isEditingEvent, setIsEditingEvent] = useState(false);
    const [imageModalSrc, setImageModalSrc] = useState('');
    const [showImageModal, setShowImageModal] = useState(false);
    const [toast, setToast] = useState({ message: '', type: 'info', visible: false });
    const [rejectReason, setRejectReason] = useState('');
    const [showRejectModal, setShowRejectModal] = useState(false);
    const [rejectEventId, setRejectEventId] = useState(null);
    const [showSettingsModal, setShowSettingsModal] = useState(false);

    const toastTimerRef = useRef(null);
    const mainContentRef = useRef(null);
    const scrollPositionRef = useRef(0);

    const [newEvent, setNewEvent] = useState({
        id: null, name: '', startDateTime: '', endDateTime: '', alertLevel: 'WHITE', category: 'Typhoon',
        general_weather: '', deployment: 'Draft', provinces: [], sendToAllUsers: false, reportLink: '',
        trackPositions: '', intensity: '', related_incidents: 0, remark_related_incidents: '',
        casualties: 0, remark_casualties: '', power_status: '', remark_power_status: '',
        communication_lines: '', remark_communication_lines: '', damage_facilities: '',
        remark_damage_facilities: '', work_suspension: false, remark_work_suspension: '',
        assistance_provided: '', remark_assistance_provided: '', imageUrl: '', status: 'approved',
        rejectionReason: ''
    });

    // Injecting CSS Dynamic Styles via Document Object Hook
    useEffect(() => {
        const styleId = "embedded-dashboard-styles";
        if (!document.getElementById(styleId)) {
            const css = `
                .dashboard-container { display: flex; font-family: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; background-color: #f7fafc; min-height: 100vh; width: 100%; color: #2d3748; overflow-y: auto; }
                .sidebar { width: 260px; background: #1a202c; color: #fff; display: flex; flex-direction: column; padding: 24px 16px; flex-shrink: 0; box-shadow: 2px 0 10px rgba(0,0,0,0.1); }
                .sidebar-brand { font-size: 20px; font-weight: 700; color: #4299e1; margin-bottom: 32px; padding-left: 12px; letter-spacing: 0.5px; }
                .sidebar-link { background: transparent; border: none; color: #cbd5e0; width: 100%; padding: 12px 16px; text-align: left; font-size: 14px; border-radius: 6px; cursor: pointer; margin-bottom: 8px; font-weight: 500; transition: all 0.2s ease; }
                .sidebar-link:hover, .sidebar-link.active { background: #2d3748; color: #fff; }
                .sidebar-logout { margin-top: auto; background: rgba(229, 62, 62, 0.1); border: 1px solid rgba(229, 62, 62, 0.2); color: #feb2b2; width: 100%; padding: 12px 16px; text-align: left; border-radius: 6px; cursor: pointer; font-size: 14px; font-weight: 500; transition: all 0.2s ease; }
                .sidebar-logout:hover { background: #e53e3e; color: #fff; }
                .main-content { flex: 1; padding: 32px; overflow-x: hidden; }
                .dashboard-header { display: flex; justify-content: space-between; align-items: center; border-bottom: 1px solid #e2e8f0; padding-bottom: 20px; margin-bottom: 24px; }
                .dashboard-header h1 { font-size: 24px; font-weight: 700; color: #1a202c; margin: 0; }
                .user-profile-badge { font-size: 14px; background: #edf2f7; padding: 8px 16px; border-radius: 20px; border: 1px solid #e2e8f0; }
                .action-toolbar { display: flex; gap: 12px; margin-bottom: 24px; flex-wrap: wrap; align-items: center; }
                .form-select, .form-input, .search-input { background: #fff; border: 1px solid #cbd5e0; padding: 10px 14px; border-radius: 6px; font-size: 14px; outline: none; box-shadow: sm; width: 100%; transition: border-color 0.2s; }
                .form-select:focus, .form-input:focus { border-color: #4299e1; }
                .form-select { cursor: pointer; width: auto; min-width: 200px; }
                .view-btn { background: #fff; border: 1px solid #cbd5e0; padding: 10px 16px; border-radius: 6px; font-size: 14px; cursor: pointer; font-weight: 500; display: inline-flex; align-items: center; gap: 6px; transition: all 0.15s; }
                .view-btn:hover { background: #f7fafc; border-color: #a0aec0; }
                .add-mun-btn { background: #3182ce; color: #fff; border: none; padding: 10px 18px; border-radius: 6px; font-size: 14px; cursor: pointer; font-weight: 500; transition: background 0.15s; }
                .add-mun-btn:hover { background: #2b6cb0; }
                .danger { background: #fff; border: 1px solid #feb2b2; color: #e53e3e; }
                .danger:hover { background: #fff5f5; border-color: #fc8181; }
                .weather-card { padding: 16px; background: #ebf8ff; border-left: 4px solid #3182ce; border-radius: 4px; margin-bottom: 24px; font-size: 14px; line-height: 1.5; color: #2b6cb0; }
                .dashboard-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(450px, 1fr)); gap: 24px; }
                .content-box { background: #fff; border: 1px solid #e2e8f0; padding: 24px; border-radius: 8px; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.05); }
                .content-box h3 { margin-top: 0; font-size: 16px; font-weight: 600; color: #2d3748; border-bottom: 1px solid #edf2f7; padding-bottom: 12px; margin-bottom: 16px; }
                .damage-table { width: 100%; border-collapse: collapse; margin-top: 8px; font-size: 14px; }
                .damage-table th, .damage-table td { padding: 12px; border-bottom: 1px solid #edf2f7; text-align: left; }
                .damage-table th { font-weight: 600; color: #718096; background: #f7fafc; }
                .modal-overlay { position: fixed; top:0; left:0; right:0; bottom:0; background: rgba(0,0,0,0.4); display: flex; align-items: center; justify-content: center; z-index: 1000; padding: 20px; animation: fadeIn 0.2s ease-out; }
                .modal-content { background: #fff; padding: 28px; border-radius: 8px; width: 100%; max-width: 520px; box-shadow: 0 20px 25px -5px rgba(0,0,0,0.1); position: relative; max-height: 90vh; overflow-y: auto; }
                .modal-content.large-modal { max-width: 700px; }
                .modal-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
                .modal-header h3 { margin: 0; font-size: 18px; font-weight: 600; }
                .modal-close { background: none; border: none; font-size: 24px; cursor: pointer; color: #a0aec0; }
                .modal-close:hover { color: #4a5568; }
                .event-form .form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin-bottom: 16px; }
                .event-form .form-group { display: flex; flex-direction: column; gap: 6px; }
                .event-form label { font-size: 13px; font-weight: 500; color: #4a5568; }
                .datetime-row { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin-bottom: 16px; }
                .datetime-group { display: flex; flex-direction: column; gap: 6px; }
                .modal-footer { display: flex; justify-content: flex-end; gap: 12px; margin-top: 24px; padding-top: 16px; border-top: 1px solid #edf2f7; }
                .cancel-btn { background: #fff; border: 1px solid #cbd5e0; padding: 10px 20px; border-radius: 6px; font-size: 14px; cursor: pointer; }
                .submit-btn { background: #3182ce; color: #fff; border: none; padding: 10px 20px; border-radius: 6px; font-size: 14px; cursor: pointer; font-weight: 500; }
                .toast-banner { position: fixed; bottom: 24px; right: 24px; background: #2d3748; color: #fff; padding: 12px 24px; border-radius: 6px; box-shadow: 0 10px 15px -3px rgba(0,0,0,0.1); z-index: 1100; font-size: 14px; display: flex; align-items: center; gap: 8px; animation: slideIn 0.2s cubic-bezier(0.1, 0.8, 0.2, 1); }
                .toast-banner.success { background: #38a169; }
                .toast-banner.warning { background: #dd6b20; }
                .toast-banner.error { background: #e53e3e; }
                @keyframes slideIn { from { transform: translateY(12px); opacity:0; } to { transform: translateY(0); opacity:1; } }
                @keyframes fadeIn { from { opacity:0; } to { opacity:1; } }
            `;
            const style = document.createElement('style');
            style.id = styleId;
            style.type = 'text/css';
            style.appendChild(document.createTextNode(css));
            document.head.appendChild(style);
        }
    }, []);

    // ----------------------------- LOGIC & EFFECT ENGINE -----------------------------
    const handleScroll = useCallback(() => {
        if (mainContentRef.current) {
            scrollPositionRef.current = mainContentRef.current.scrollTop;
        }
    }, []);

    useEffect(() => {
        if (mainContentRef.current && scrollPositionRef.current > 0) {
            mainContentRef.current.scrollTop = scrollPositionRef.current;
        }
    });

    useEffect(() => {
        scrollPositionRef.current = 0;
        if (mainContentRef.current) mainContentRef.current.scrollTop = 0;
    }, [activeMenu]);

    const filteredEvents = useMemo(() => {
        const term = searchTerm.toLowerCase();
        return events.filter(event => {
            const matchSearch = (event.name || '').toLowerCase().includes(term) ||
                (event.alertLevel || '').toLowerCase().includes(term) ||
                (event.category || '').toLowerCase().includes(term);
            if (statusFilter === 'all') return matchSearch;
            return matchSearch && event.status === statusFilter;
        });
    }, [events, searchTerm, statusFilter]);

    useEffect(() => { saveToStorage('dash_activeMenu', activeMenu); }, [activeMenu]);
    useEffect(() => { saveToStorage('dash_officesData', officesData); }, [officesData]);
    useEffect(() => { saveToStorage('dash_events', events); }, [events]);
    useEffect(() => { saveToStorage(TYPHOON_HISTORY_KEY, typhoonHistory); }, [typhoonHistory]);
    useEffect(() => { saveToStorage('dash_users', users); }, [users]);
    useEffect(() => { saveToStorage('dash_notifications', notifications); }, [notifications]);

    useEffect(() => {
        const getWeather = async () => {
            setWeatherLoading(true);
            const weather = await fetchLiveWeather();
            setLiveWeather(weather);
            setWeatherLoading(false);
        };
        getWeather();
        const interval = setInterval(getWeather, 120000);
        return () => clearInterval(interval);
    }, []);

    const rawRole = currentUser?.role ?? '';
    const normalizedRole = rawRole.toString().trim().toUpperCase();
    const isSuperAdmin = normalizedRole.includes('SADMIN') || normalizedRole.includes('SUPER');
    const isAdmin = !isSuperAdmin && (normalizedRole === 'ADMIN' || normalizedRole.includes('ADMIN'));
    const isUser = normalizedRole === 'USER';
    const canEditEvents = isSuperAdmin || isAdmin;
    const canDeployEvents = isSuperAdmin;

    useEffect(() => {
        if (isUser && currentUser?.office) setSelectedOffice(currentUser.office);
    }, [isUser, currentUser]);

    const activeEvent = events.find(e => e.deployment === 'Deployed') || events[0];

    const showToast = (message, type = 'info') => {
        if (toastTimerRef.current) clearTimeout(toastTimerRef.current);
        setToast({ message, type, visible: true });
        toastTimerRef.current = setTimeout(() => {
            setToast(prev => ({ ...prev, visible: false }));
        }, 3200);
    };

    const addNotification = (title, message, type = 'info') => {
        const newNotif = { id: Date.now(), title, message, type, timestamp: new Date().toISOString(), read: false };
        setNotifications(prev => [newNotif, ...prev].slice(0, 50));
        showToast(message, type);
    };

    // ----------------------------- COMPONENT PARAM HANDLERS -----------------------------
    const handleNewEventFieldChange = (field, value) => {
        setNewEvent(prev => ({ ...prev, [field]: value }));
    };

    const handleEditFormFieldChange = (field, value) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    };

    const handleSignalChange = (municipality, value) => {
        setFormData(prev => ({
            ...prev,
            warning_signals: { ...prev.warning_signals, [municipality]: parseInt(value) || 0 }
        }));
    };

    const handleAddMunicipality = () => {
        if (newMunicipality.trim() && !formData.municipalities.includes(newMunicipality)) {
            setFormData({
                ...formData,
                municipalities: [...formData.municipalities, newMunicipality],
                warning_signals: { ...formData.warning_signals, [newMunicipality]: newSignal }
            });
            setNewMunicipality('');
            setNewSignal(1);
        }
    };

    const handleRemoveMunicipality = (municipality) => {
        const updatedMunicipalities = formData.municipalities.filter(m => m !== municipality);
        const updatedSignals = { ...formData.warning_signals };
        delete updatedSignals[municipality];
        setFormData({ ...formData, municipalities: updatedMunicipalities, warning_signals: updatedSignals });
    };

    const handleEditToggle = () => {
        if (selectedOffice === 'PSTO-Region-1') {
            showToast('Cannot write data nodes to root summarizer directly.', 'warning');
            return;
        }
        if (!editMode) {
            setFormData(deepClone(officesData[selectedOffice]));
        }
        setEditMode(!editMode);
    };

    const handleSave = () => {
        setOfficesData(prev => ({ ...prev, [selectedOffice]: formData }));
        setEditMode(false);
        addNotification('Parameters Saved', `Successfully updated tracking indices for ${selectedOffice}`, 'success');
    };

    // ----------------------------- MONITORED CYCLONE LOGIC -----------------------------
    const openAddEventModal = () => {
        setNewEvent({
            id: null, name: '', startDateTime: '', endDateTime: '', alertLevel: 'WHITE', category: 'Typhoon',
            general_weather: '', deployment: 'Draft', provinces: [], sendToAllUsers: false, reportLink: '',
            trackPositions: '', intensity: '', related_incidents: 0, remark_related_incidents: '',
            casualties: 0, remark_casualties: '', power_status: '', remark_power_status: '',
            communication_lines: '', remark_communication_lines: '', damage_facilities: '',
            remark_damage_facilities: '', work_suspension: false, remark_work_suspension: '',
            assistance_provided: '', remark_assistance_provided: '', imageUrl: '', status: 'approved',
            rejectionReason: ''
        });
        setIsEditingEvent(false);
        setShowAddModal(true);
    };

    const handleAddEventSubmit = (e) => {
        e.preventDefault();
        if (!newEvent.name.trim()) return;

        if (isEditingEvent) {
            setEvents(prev => prev.map(ev => ev.id === newEvent.id ? { ...newEvent } : ev));
            showToast('Incident structural event mutated.', 'success');
        } else {
            const created = { ...newEvent, id: Date.now(), date: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) };
            setEvents(prev => [created, ...prev]);
            showToast('New system event registered.', 'success');
        }
        setShowAddModal(false);
    };

    const handleDeployEvent = (eventId) => {
        setEvents(prev => prev.map(ev => ({
            ...ev,
            deployment: ev.id === eventId ? 'Deployed' : 'Draft'
        })));
        showToast('Selected tracking node went live.', 'success');
    };

    const handleDeleteEvent = (eventId) => {
        if (window.confirm('Purge structural target completely?')) {
            setEvents(prev => prev.filter(ev => ev.id !== eventId));
            showToast('Event track deleted.', 'error');
        }
    };

    const handleEditEvent = (event) => {
        setNewEvent({ ...event });
        setIsEditingEvent(true);
        setShowAddModal(true);
    };

    const confirmRejectEvent = () => {
        setEvents(prev => prev.map(ev => ev.id === rejectEventId ? { ...ev, status: 'rejected', rejectionReason: rejectReason } : ev));
        setShowRejectModal(false);
        setRejectReason('');
        showToast('System event modification disapproved.', 'warning');
    };

    // ----------------------------- DATA GENERATION ENGINES -----------------------------
    const buildReportHtml = () => {
        const generatedAt = new Date().toLocaleString();
        const reportOffices = Object.entries(officesData);

        const summaryRows = reportOffices.map(([officeName, officeData]) => {
            const warningTags = Object.entries(officeData.warning_signals || {}).map(([mun, signal]) => `${mun} (S${signal})`).join('; ') || 'None';
            return `<tr><td>${officeName}</td><td>${warningTags}</td><td>${officeData.general_weather || 'N/A'}</td></tr>`;
        }).join('');

        const incidentsRows = reportOffices.map(([officeName, officeData]) => `<tr><td>${officeName}</td><td>${officeData.related_incidents ?? 0}</td><td>${officeData.remark_related_incidents || '-'}</td></tr>`).join('');
        const casualtiesRows = reportOffices.map(([officeName, officeData]) => `<tr><td>${officeName}</td><td>${officeData.casualties ?? 0}</td><td>${officeData.remark_casualties || '-'}</td></tr>`).join('');
        const powerRows = reportOffices.map(([officeName, officeData]) => `<tr><td>${officeName}</td><td>${officeData.power_status || 'Operational'}</td><td>${officeData.remark_power_status || '-'}</td></tr>`).join('');
        const commsRows = reportOffices.map(([officeName, officeData]) => `<tr><td>${officeName}</td><td>${officeData.communication_lines || 'Operational'}</td><td>${officeData.remark_communication_lines || '-'}</td></tr>`).join('');
        const workRows = reportOffices.map(([officeName, officeData]) => `<tr><td>${officeName}</td><td>${officeData.work_suspension ? 'Suspended' : 'Normal Operations'}</td><td>${officeData.remark_work_suspension || '-'}</td></tr>`).join('');

        return `
      <!DOCTYPE html>
      <html>
      <head>
        <meta charset="UTF-8">
        <title>DOST-1 Situational Report Frame</title>
        <style>
          body { font-family: Arial, sans-serif; margin: 30px; line-height: 1.4; color: #333; }
          h1 { font-size: 20px; text-align: center; border-bottom: 2px solid #333; padding-bottom: 10px; margin-bottom: 20px; }
          h3 { font-size: 14px; background: #f2f2f2; padding: 6px; margin: 20px 0 10px 0; border-left: 4px solid #333; }
          table { width: 100%; border-collapse: collapse; margin-bottom: 15px; font-size: 12px; }
          th, td { border: 1px solid #aaa; padding: 8px; text-align: left; }
          th { background: #fafafa; font-weight: bold; }
        </style>
      </head>
      <body>
        <h1>SITUATIONAL INCIDENT ASSESSMENT REPO-FRAME</h1>
        <p><strong>System Event Focus:</strong> ${activeEvent?.name || 'Unspecified track'} | <strong>Issued:</strong> ${generatedAt}</p>
        <h3>I. MUNICIPAL CYCLONE WEATHER CONDITION CONFIG</h3>
        <table><thead><tr><th>OFFICE</th><th>WARNING SIGNALS</th><th>GENERAL WEATHER</th></tr></thead><tbody>${summaryRows}</tbody></table>
        <h3>II. OPERATIONAL STRUCTURAL IMPACT INDICATORS</h3>
        <h4>A. Incident Logs</h4>
        <table><thead><tr><th>OFFICE</th><th>INCIDENTS</th><th>REMARKS</th></tr></thead><tbody>${incidentsRows}</tbody></table>
        <h4>B. Casualty Indices</h4>
        <table><thead><tr><th>OFFICE</th><th>CASUALTIES</th><th>REMARKS</th></tr></thead><tbody>${casualtiesRows}</tbody></table>
        <h4>C. Electrical Infrastructure Power Grid</h4>
        <table><thead><tr><th>OFFICE</th><th>STATUS</th><th>REMARKS</th></tr></thead><tbody>${powerRows}</tbody></table>
        <h4>D. Telecommunication Systems Lines</h4>
        <table><thead><tr><th>OFFICE</th><th>STATUS</th><th>REMARKS</th></tr></thead><tbody>${commsRows}</tbody></table>
        <h4>E. Workplace Availability / Disruptions</h4>
        <table><thead><tr><th>OFFICE</th><th>SUSPENSION STATE</th><th>REMARKS</th></tr></thead><tbody>${workRows}</tbody></table>
      </body>
      </html>`;
    };

    const handleGenerateReport = () => {
        const reportHtml = buildReportHtml();
        const printWindow = window.open('', '_blank');
        if (!printWindow) {
            showToast('Pop-up framework intercepted. Toggle permissions context.', 'warning');
            return;
        }
        printWindow.document.write(reportHtml);
        printWindow.document.close();
    };

    const handleDownloadDoc = () => {
        const blob = new Blob([buildReportHtml()], { type: 'application/msword' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `SITREP_${activeEvent?.name || 'INCIDENT'}.doc`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleExportExcel = () => {
        const sheetData = [['PSTO Office Sub-Node', 'General Weather Track', 'Incidents Reported', 'Casualties Index', 'Power Infrastructure Status', 'Comms Line State', 'Work Suspended Status']];
        Object.entries(officesData).forEach(([office, data]) => {
            sheetData.push([
                office, data.general_weather || '', data.related_incidents ?? 0, data.casualties ?? 0,
                data.power_status || '', data.communication_lines || '', data.work_suspension ? 'Yes' : 'No'
            ]);
        });
        const ws = XLSX.utils.aoa_to_sheet(sheetData);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'DRRM_Incident_Matrix');
        XLSX.writeFile(wb, `DRRM_Report_${Date.now()}.xlsx`);
    };

    const currentOfficeData = officesData[selectedOffice] || {};
    const displayEvent = editMode ? formData : currentOfficeData;

    // ----------------------------- INTERNAL SUB-MODALS -----------------------------
    const AddEventModal = () => (
        <div className="modal-overlay" onClick={() => setShowAddModal(false)}>
            <div className="modal-content large-modal" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h3>{isEditingEvent ? '✏️ Modify Tracked Cyclone Schema' : '🌪️ Register New Tracking Blueprint'}</h3>
                    <button type="button" className="modal-close" onClick={() => setShowAddModal(false)}>×</button>
                </div>
                <form onSubmit={handleAddEventSubmit} className="event-form">
                    <div className="form-row">
                        <div className="form-group">
                            <label>Event Name Designation *</label>
                            <input type="text" value={newEvent.name} onChange={(e) => handleNewEventFieldChange('name', e.target.value)} required placeholder="e.g., Typhoon Man-yi" className="form-input" />
                        </div>
                    </div>
                    <div className="form-row">
                        <div className="form-group">
                            <label>Alert Escalation Mode</label>
                            <select value={newEvent.alertLevel} onChange={(e) => handleNewEventFieldChange('alertLevel', e.target.value)} className="form-select" style={{ width: '100%' }}>
                                <option value="WHITE">⚪ WHITE ALERT CODE</option>
                                <option value="BLUE">🔵 BLUE ALERT CODE</option>
                                <option value="RED">🔴 RED ALERT CODE</option>
                            </select>
                        </div>
                        <div className="form-group">
                            <label>Meteorological Category Designation</label>
                            <select value={newEvent.category} onChange={(e) => handleNewEventFieldChange('category', e.target.value)} className="form-select" style={{ width: '100%' }}>
                                <option value="Super Typhoon">🌪️ Super Typhoon</option>
                                <option value="Typhoon">🌀 Typhoon</option>
                                <option value="Severe Tropical Storm">🌧️ Severe Tropical Storm</option>
                                <option value="Tropical Storm">🌧️ Tropical Storm</option>
                                <option value="Tropical Depression">☁️ Tropical Depression</option>
                            </select>
                        </div>
                    </div>
                    <div className="datetime-row">
                        <div className="datetime-group">
                            <label>Track Intersection Inception</label>
                            <input type="datetime-local" value={newEvent.startDateTime} onChange={(e) => handleNewEventFieldChange('startDateTime', e.target.value)} className="form-input" />
                        </div>
                        <div className="datetime-group">
                            <label>Forecast Structural Bounds End</label>
                            <input type="datetime-local" value={newEvent.endDateTime} onChange={(e) => handleNewEventFieldChange('endDateTime', e.target.value)} className="form-input" />
                        </div>
                    </div>
                    <div className="form-row">
                        <div className="form-group">
                            <label>Coordinates Track Position Vector</label>
                            <input type="text" value={newEvent.trackPositions} onChange={(e) => handleNewEventFieldChange('trackPositions', e.target.value)} placeholder="e.g., 16.2N, 121.4E" className="form-input" />
                        </div>
                        <div className="form-group">
                            <label>Max Sustained Internal Winds</label>
                            <input type="text" value={newEvent.intensity} onChange={(e) => handleNewEventFieldChange('intensity', e.target.value)} placeholder="e.g., 165 km/h" className="form-input" />
                        </div>
                    </div>
                    <div className="modal-footer">
                        <button type="button" className="cancel-btn" onClick={() => setShowAddModal(false)}>Discard</button>
                        <button type="submit" className="submit-btn">{isEditingEvent ? 'Commit Schema Changes' : 'Write Event Track'}</button>
                    </div>
                </form>
            </div>
        </div>
    );

    return (
        <div className="dashboard-container" ref={mainContentRef} onScroll={handleScroll}>
            {/* Structural Navigation Sidebar */}
            <div className="sidebar">
                <div className="sidebar-brand">DOST R1 SYSTEM</div>
                <button type="button" className={`sidebar-link ${activeMenu === 'dashboard' ? 'active' : ''}`} onClick={() => setActiveMenu('dashboard')}>📊 Assessment Panels</button>
                <button type="button" className={`sidebar-link ${activeMenu === 'events' ? 'active' : ''}`} onClick={() => setActiveMenu('events')}>🌪️ Tracker Registry</button>
                <button type="button" className="sidebar-logout" onClick={onLogout}>🚪 Terminate Session</button>
            </div>

            {/* Core Display Canvas Workspace */}
            <div className="main-content">
                {activeMenu === 'dashboard' ? (
                    <>
                        <div className="dashboard-header">
                            <h1>Disaster Contingency Management Architecture</h1>
                            <div className="user-profile-badge">
                                Terminal Focus Node: <strong>{selectedOffice}</strong>
                            </div>
                        </div>

                        {/* Node Controller & Data Export Interface Pipeline */}
                        <div className="action-toolbar">
                            <select value={selectedOffice} onChange={(e) => { setSelectedOffice(e.target.value); setEditMode(false); }} className="form-select">
                                {Object.keys(officesData).map(name => <option key={name} value={name}>{name}</option>)}
                            </select>
                            <button type="button" className="view-btn" onClick={handleEditToggle}>
                                {editMode ? '❌ Close Operational Form' : '✏️ Write Parameters Context'}
                            </button>
                            {editMode && <button type="button" className="add-mun-btn" onClick={handleSave}>💾 Flush Data to Memory</button>}

                            <div style={{ marginLeft: 'auto', display: 'flex', gap: '8px' }}>
                                <button type="button" className="view-btn" onClick={handleGenerateReport}>🖨️ Construct SitRep Document</button>
                                <button type="button" className="view-btn" onClick={handleDownloadDoc}>📄 Generate Binary DOC</button>
                                <button type="button" className="view-btn" onClick={handleExportExcel}>📊 Compile Spreadsheets</button>
                            </div>
                        </div>

                        {/* Real-time Atmospheric Feed Window */}
                        <div className="weather-card">
                            <strong>🌤️ Synoptic Weather Telemetry Stream (Region 1 Center Bounds): </strong>
                            {liveWeather ? `${liveWeather.condition} — Temperature Vector: ${liveWeather.temp}°C | Wind speed calculations: ${liveWeather.windSpeed} km/h` : 'Interrogating open-meteo arrays...'}
                        </div>

                        {/* Analytics Config Matrix Layout */}
                        <div className="dashboard-grid">
                            {/* Warning Matrix Node */}
                            <div className="content-box">
                                <h3>⚠️ Sub-Node Warnings Threshold</h3>
                                {editMode ? (
                                    <div>
                                        <div style={{ display: 'flex', gap: '10px', marginBottom: '16px' }}>
                                            <input type="text" placeholder="Incorporate Municipality target..." value={newMunicipality} onChange={e => setNewMunicipality(e.target.value)} className="form-input" />
                                            <select value={newSignal} onChange={e => setNewSignal(parseInt(e.target.value))} className="form-select" style={{ minWidth: '110px' }}>
                                                {[1, 2, 3, 4, 5].map(s => <option key={s} value={s}>Signal {s}</option>)}
                                            </select>
                                            <button type="button" className="add-mun-btn" onClick={handleAddMunicipality}>+</button>
                                        </div>
                                        <ul style={{ paddingLeft: '4px', listStyleType: 'none' }}>
                                            {(displayEvent.municipalities || []).map(mun => (
                                                <li key={mun} style={{ margin: '10px 0', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: '#f7fafc', padding: '8px 12px', borderRadius: '6px', border: '1px solid #edf2f7' }}>
                                                    <span>{mun} — <strong>TCWS Level {displayEvent.warning_signals?.[mun] || 0}</strong></span>
                                                    <button type="button" onClick={() => handleRemoveMunicipality(mun)} style={{ border: 'none', background: 'transparent', color: '#e53e3e', cursor: 'pointer', fontOrder: '600' }}>Purge</button>
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                ) : (
                                    <table className="damage-table">
                                        <thead>
                                            <tr><th>Target Sector Bounds</th><th>TCWS Alert Level Matrix</th></tr>
                                        </thead>
                                        <tbody>
                                            {Object.entries(currentOfficeData.warning_signals || {}).map(([m, s]) => (
                                                <tr key={m}><td>{m}</td><td><span style={{ color: '#dd6b20', fontWeight: '700' }}>TCWS Level {s}</span></td></tr>
                                            ))}
                                            {Object.keys(currentOfficeData.warning_signals || {}).length === 0 && <tr><td colSpan="2" style={{ color: '#a0aec0', padding: '16px 0' }}>No active metrics mapped to local matrix structure.</td></tr>}
                                        </tbody>
                                    </table>
                                )}
                            </div>

                            {/* Impact Variables Entry Field Grid Node */}
                            <div className="content-box">
                                <h3>📊 Critical System Disruption Registers</h3>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
                                    <div>
                                        <label style={{ display: 'block', fontSize: '13px', marginBottom: '6px', fontWeight: '500' }}>Active System Incidents Count</label>
                                        <input type="number" disabled={!editMode} value={displayEvent.related_incidents || 0} onChange={e => handleEditFormFieldChange('related_incidents', parseInt(e.target.value) || 0)} className="form-input" />
                                    </div>
                                    <div>
                                        <label style={{ display: 'block', fontSize: '13px', marginBottom: '6px', fontWeight: '500' }}>Structural Human Casualties Vector</label>
                                        <input type="number" disabled={!editMode} value={displayEvent.casualties || 0} onChange={e => handleEditFormFieldChange('casualties', parseInt(e.target.value) || 0)} className="form-input" />
                                    </div>
                                    <div>
                                        <label style={{ display: 'block', fontSize: '13px', marginBottom: '6px', fontWeight: '500' }}>Power Grids Availability Infrastructure Remarks</label>
                                        <input type="text" disabled={!editMode} value={displayEvent.power_status || ''} onChange={e => handleEditFormFieldChange('power_status', e.target.value)} placeholder="e.g., 40% Intermittent Outage" className="form-input" />
                                    </div>
                                    <div>
                                        <label style={{ display: 'block', fontSize: '13px', marginBottom: '6px', fontWeight: '500' }}>Telecommunication Infrastructure Connectivity Context</label>
                                        <input type="text" disabled={!editMode} value={displayEvent.communication_lines || ''} onChange={e => handleEditFormFieldChange('communication_lines', e.target.value)} placeholder="e.g., Cellular service down inside Sector B" className="form-input" />
                                    </div>
                                    <div style={{ marginTop: '6px', padding: '8px 0' }}>
                                        <label style={{ display: 'flex', gap: '10px', alignItems: 'center', cursor: 'pointer', fontSize: '14px' }}>
                                            <input type="checkbox" disabled={!editMode} checked={!!displayEvent.work_suspension} onChange={e => handleEditFormFieldChange('work_suspension', e.target.checked)} style={{ width: '16px', height: '16px' }} />
                                            <strong>Workplace Suspensions Declared Across Context Bounds</strong>
                                        </label>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </>
                ) : (
                    /* Track Registry Layout View Screen */
                    <div className="events-management-pane">
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
                            <h2 style={{ margin: '0', fontSize: '22px', fontWeight: '700' }}>Cyclone Track Structural Registry Matrix</h2>
                            {canEditEvents && <button type="button" className="add-mun-btn" onClick={openAddEventModal}>+ Blueprint Tracking Windows</button>}
                        </div>

                        <div style={{ marginBottom: '20px' }}>
                            <input type="text" placeholder="Query Event Tracking Blueprints..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="search-input" style={{ maxWidth: '400px' }} />
                        </div>

                        <div style={{ background: '#fff', border: '1px solid #e2e8f0', borderRadius: '8px', overflow: 'hidden', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' }}>
                            <table className="damage-table">
                                <thead>
                                    <tr style={{ background: '#f7fafc' }}>
                                        <th>Target Key Designation</th>
                                        <th>Meteorological Category</th>
                                        <th>Threat Escalation Vector</th>
                                        <th>Live Core Scope Status</th>
                                        <th>System Operation Intersects</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {filteredEvents.map(event => (
                                        <tr key={event.id}>
                                            <td><strong>{event.name}</strong></td>
                                            <td>{event.category}</td>
                                            <td>
                                                <span style={{ padding: '4px 10px', background: event.alertLevel === 'RED' ? '#fff5f5' : '#f7fafc', color: event.alertLevel === 'RED' ? '#c53030' : '#4a5568', borderRadius: '4px', fontSize: '12px', fontWeight: '700', border: event.alertLevel === 'RED' ? '1px solid #fed7d7' : '1px solid #e2e8f0' }}>
                                                    {event.alertLevel} STATUS
                                                </span>
                                            </td>
                                            <td>
                                                <span style={{ color: event.deployment === 'Deployed' ? '#2f855a' : '#718096', fontWeight: '700' }}>
                                                    {event.deployment}
                                                </span>
                                            </td>
                                            <td>
                                                <button type="button" className="view-btn" onClick={() => handleEditEvent(event)} style={{ marginRight: '8px', padding: '6px 12px' }}>✏️ Config</button>
                                                {canDeployEvents && event.deployment !== 'Deployed' && (
                                                    <button type="button" className="add-mun-btn" onClick={() => handleDeployEvent(event.id)} style={{ marginRight: '8px', padding: '6px 14px' }}>🚀 Deploy Track</button>
                                                )}
                                                <button type="button" className="view-btn danger" onClick={() => handleDeleteEvent(event.id)} style={{ padding: '6px 12px' }}>🗑️ Delete</button>
                                            </td>
                                        </tr>
                                    ))}
                                    {filteredEvents.length === 0 && (
                                        <tr><td colSpan="5" style={{ padding: '32px', textAlign: 'center', color: '#a0aec0' }}>No target variables found corresponding to active criteria filter inputs.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </div>

            {/* Dynamic Rendering Framework Component Context Modals */}
            {showAddModal && <AddEventModal />}
            {showSettingsModal && (
                <div className="modal-overlay" onClick={() => setShowSettingsModal(false)}>
                    <div className="modal-content" onClick={e => e.stopPropagation()}>
                        <h3>Core System Architecture Configurations</h3>
                        <div className="modal-footer">
                            <button type="button" className="cancel-btn" onClick={() => setShowSettingsModal(false)}>Dismiss</button>
                        </div>
                    </div>
                </div>
            )}
            {showRejectModal && (
                <div className="modal-overlay" onClick={() => setShowRejectModal(false)}>
                    <div className="modal-content" onClick={e => e.stopPropagation()}>
                        <h3>Disapprove Track Configuration State</h3>
                        <textarea className="form-input" placeholder="Document missing variables or structural adjustments requirements..." value={rejectReason} onChange={(e) => setRejectReason(e.target.value)} style={{ width: '100%', height: '90px', marginTop: '12px', resize: 'none' }} />
                        <div className="modal-footer">
                            <button type="button" className="cancel-btn" onClick={() => setShowRejectModal(false)}>Cancel Action</button>
                            <button type="button" className="add-mun-btn danger" onClick={confirmRejectEvent}>Confirm Disapproval Execution</button>
                        </div>
                    </div>
                </div>
            )}
            {showImageModal && imageModalSrc && (
                <div className="modal-overlay" onClick={() => setShowImageModal(false)}>
                    <div className="modal-content" style={{ padding: '12px', maxWidth: '800px', background: 'transparent', boxShadow: 'none' }}>
                        <img src={imageModalSrc} alt="High resolution context telemetry data frame map link vector visual representation visualization" style={{ width: '100%', height: 'auto', borderRadius: '6px' }} />
                    </div>
                </div>
            )}

            {/* Application Feedback Layer */}
            {toast.visible && (
                <div className={`toast-banner ${toast.type === 'success' ? 'success' : toast.type === 'warning' ? 'warning' : toast.type === 'error' ? 'error' : ''}`}>
                    <span>{toast.message}</span>
                </div>
            )}
        </div>
    );
};

export default Dashboard;
